/**
 * The props passed to the Checkbox and Switch components.
 */
export interface ToggleBaseProps {
    /**
     * The value of the component.
     */
    value?: any;
    /**
     * The checked state of the component.
     */
    checked?: any;
    /**
     * The default checked state of the component.
     */
    defaultChecked?: any;
}
